 10→export function SnippetMenu({ isDarkMode, onSelect, onClose }: SnippetMenuProps) {
 11→  const [query, setQuery] = useState('');
 12→  const [selectedIndex, setSelectedIndex] = useState(0);
 13→  const inputRef = useRef<HTMLInputElement>(null);
 14→  const listRef = useRef<HTMLDivElement>(null);
 15→
 16→  const filtered = useMemo(() => filterSnippets(query), [query]);
 17→  const grouped = useMemo(() => {
 18→    if (!query.trim()) return getSnippetsByCategory();
 19→    const items = filtered;
 20→    if (items.length === 0) return [];
 21→    return [{ category: 'results' as const, label: 'Results', items }];
 22→  }, [query, filtered]);
 23→  const flatItems = useMemo(() => grouped.flatMap(g => g.items), [grouped]);
 24→
 25→  useEffect(() => {
 26→    inputRef.current?.focus();
 27→  }, []);
 28→
 29→  useEffect(() => {
 30→    setSelectedIndex(0);
 31→  }, [query]);
 32→
 33→  useEffect(() => {
 34→    const active = listRef.current?.querySelector('[data-active="true"]');
 35→    active?.scrollIntoView({ block: 'nearest' });
 36→  }, [selectedIndex]);
 37→
 38→  const handleKeyDown = useCallback(
 39→    (e: React.KeyboardEvent) => {
 40→      if (e.key === 'Escape') {
 41→        e.preventDefault();
 42→        onClose();
 43→        return;
 44→      }
 45→      if (e.key === 'ArrowDown') {
 46→        e.preventDefault();
 47→        setSelectedIndex(i => Math.min(i + 1, flatItems.length - 1));
 48→        return;
 49→      }
 50→      if (e.key === 'ArrowUp') {
 51→        e.preventDefault();
 52→        setSelectedIndex(i => Math.max(i - 1, 0));
 53→        return;
 54→      }
 55→      if (e.key === 'Enter') {
 56→        e.preventDefault();
 57→        if (flatItems[selectedIndex]) onSelect(flatItems[selectedIndex]);
 58→        return;
 59→      }
 60→    },
 61→    [flatItems, selectedIndex, onSelect, onClose],
 62→  );
 63→
 64→  const s = isDarkMode ? darkStyles : lightStyles;
 65→
 66→  return (
 67→    <div style={s.backdrop} onClick={onClose}>
 68→      <div style={s.container} onClick={e => e.stopPropagation()} onKeyDown={handleKeyDown}>
 69→        <div style={s.searchRow}>
 70→          <input
 71→            ref={inputRef}
 72→            style={s.input}
 73→            type="text"
 74→            placeholder="Find a snippet…"
 75→            value={query}
 76→            onChange={e => setQuery(e.target.value)}
 77→          />
 78→          <kbd style={s.kbd}>Esc</kbd>
 79→        </div>
 80→        <div ref={listRef} style={s.list}>
 81→          {flatItems.length === 0 && (
 82→            <div style={s.empty}>No snippets match "{query}"</div>
 83→          )}
 84→          {grouped.map(group => (
 85→            <div key={group.category}>
 86→              <div style={s.groupLabel}>{group.label}</div>
 87→              {group.items.map(item => {
 88→                const idx = flatItems.indexOf(item);
 89→                const isActive = idx === selectedIndex;
 90→                return (
 91→                  <div
 92→                    key={item.id}
 93→                    data-active={isActive}
 94→                    style={{
 95→                      ...s.item,
 96→                      ...(isActive ? s.itemActive : {}),
 97→                    }}
 98→                    onClick={() => onSelect(item)}
 99→                    onMouseEnter={() => setSelectedIndex(idx)}
100→                  >
101→                    <span style={s.itemBadge}>{item.category === 'screen' ? 'Screen' : item.category === 'structure' ? 'Struct' : 'Comp'}</span>
102→                    <span style={s.itemLabel}>{item.label}</span>
103→                    <span style={s.itemDesc}>{item.description}</span>
104→                  </div>
105→                );
106→              })}
107→            </div>
108→          ))}
109→        </div>
110→      </div>
111→    </div>
112→  );
113→}
