  1→import React, { useCallback, useEffect, useRef, useState } from 'react';
  2→import { addons } from 'storybook/internal/manager-api';
  3→import { useStorybookState } from 'storybook/internal/manager-api';
  4→import { EVENTS } from './constants';
  5→import { useIndexedDB } from './useIndexedDB';
  6→import { CodeMirrorEditor, type CodeMirrorEditorHandle } from './CodeMirrorEditor';
  7→import { SnippetMenu } from './SnippetMenu';
  8→import type { SDUISnippet } from './sduiSnippets';
  9→import JSON5 from 'json5';
 10→
 11→function idbKeyFor(storyId: string) {
 12→  return `sdui-json-${storyId}`;
 13→}
 14→
 15→function getChannel() {
 16→  try { return addons.getChannel(); } catch { return null; }
 17→}
 18→
 19→function tryParse(text: string): { parsed: any; error: string | null } {
 20→  try {
 21→    return { parsed: JSON.parse(text), error: null };
 22→  } catch {
 23→    try {
 24→      return { parsed: JSON5.parse(text), error: null };
 25→    } catch (e) {
 26→      return { parsed: null, error: (e as Error).message };
 27→    }
 28→  }
 29→}
 30→
 31→function getIsDarkMode(): boolean {
 32→  if (typeof localStorage === 'undefined') return false;
 33→  const stored = localStorage.getItem('sb-ui-theme');
 34→  if (stored) return stored === 'dark';
 35→  return typeof window !== 'undefined'
 36→    && window.matchMedia?.('(prefers-color-scheme: dark)').matches;
 37→}
 38→
 39→export function JsonEditorPanel() {
 40→  const state = useStorybookState();
 41→  const storyId = state.storyId ?? '';
 42→  const [isDarkMode, setIsDarkMode] = useState(getIsDarkMode);
 43→
 44→  const [defaultJson, setDefaultJson] = useState<string>('');
 45→  const [text, setText] = useState<string>('');
 46→  const [error, setError] = useState<string | null>(null);
 47→  const [dirty, setDirty] = useState(false);
 48→  const [snippetMenuOpen, setSnippetMenuOpen] = useState(false);
 49→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 50→  const editorRef = useRef<CodeMirrorEditorHandle>(null);
 51→  const retryRef = useRef<ReturnType<typeof setInterval> | null>(null);
 52→  const initializedRef = useRef(false);
 53→  const defaultJsonRef = useRef('');
 54→
 55→  const { stored, save, remove, ready } = useIndexedDB(idbKeyFor(storyId));
 56→
 57→  useEffect(() => {
 58→    const interval = setInterval(() => {
 59→      setIsDarkMode(getIsDarkMode());
 60→    }, 1000);
 61→    return () => {
 62→      clearInterval(interval);
 63→      if (debounceRef.current) clearTimeout(debounceRef.current);
 64→      if (retryRef.current) clearInterval(retryRef.current);
 65→    };
 66→  }, []);
 67→
 68→  useEffect(() => {
 69→    if (debounceRef.current) {
 70→      clearTimeout(debounceRef.current);
 71→      debounceRef.current = null;
 72→    }
 73→    setDefaultJson('');
 74→    defaultJsonRef.current = '';
 75→    setText('');
 76→    setDirty(false);
 77→    setError(null);
 78→    initializedRef.current = false;
 79→  }, [storyId]);
 80→
 81→  useEffect(() => {
 82→    const channel = getChannel();
 83→    if (!channel) return;
 84→
 85→    const onSetDefault = (json: string) => {
 86→      setDefaultJson(json);
 87→      defaultJsonRef.current = json;
 88→      if (retryRef.current) {
 89→        clearInterval(retryRef.current);
 90→        retryRef.current = null;
 91→      }
 92→    };
 93→
 94→    channel.on(EVENTS.SET_DEFAULT_JSON, onSetDefault);
 95→    channel.emit(EVENTS.REQUEST_DEFAULT);
 96→
 97→    let retryCount = 0;
 98→    retryRef.current = setInterval(() => {
 99→      retryCount++;
100→      if (retryCount > 40) {
101→        if (retryRef.current) clearInterval(retryRef.current);
102→        return;
103→      }
104→      channel.emit(EVENTS.REQUEST_DEFAULT);
105→    }, 200);
106→
107→    return () => {
108→      channel.off(EVENTS.SET_DEFAULT_JSON, onSetDefault);
109→      if (retryRef.current) {
110→        clearInterval(retryRef.current);
111→        retryRef.current = null;
112→      }
113→    };
114→  }, [storyId]);
115→
116→  useEffect(() => {
117→    if (!ready || !defaultJson) return;
118→    if (initializedRef.current) return;
119→    initializedRef.current = true;
120→    const initial = stored ?? defaultJson;
121→    setText(initial);
122→    editorRef.current?.setValue(initial);
123→    setDirty(!!stored);
124→    setError(null);
125→    // eslint-disable-next-line react-hooks/exhaustive-deps
126→  }, [ready, defaultJson, storyId]);
127→
128→  const handleChange = useCallback(
129→    (value: string) => {
130→      setText(value);
131→
132→      if (debounceRef.current) clearTimeout(debounceRef.current);
133→
134→      debounceRef.current = setTimeout(() => {
135→        const { parsed } = tryParse(value);
136→        if (parsed !== null) {
137→          save(value);
138→          setDirty(value !== defaultJsonRef.current);
139→          getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
140→        } else {
141→          save(value);
142→          setDirty(true);
143→        }
144→      }, 400);
145→    },
146→    [save],
147→  );
148→
149→  const handleValidationChange = useCallback(
150→    (hasErrors: boolean, message: string | null) => {
151→      setError(hasErrors ? message : null);
152→    },
153→    [],
154→  );
155→
156→  const handleReset = useCallback(() => {
157→    remove();
158→    setText(defaultJson);
159→    editorRef.current?.setValue(defaultJson);
160→    setDirty(false);
161→    setError(null);
162→    const { parsed } = tryParse(defaultJson);
163→    if (parsed !== null) {
164→      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
165→    }
166→  }, [defaultJson, remove]);
167→
168→  const handleFormat = useCallback(() => {
169→    const currentText = editorRef.current?.getValue() ?? '';
170→    const { parsed, error: parseErr } = tryParse(currentText);
171→    if (parsed !== null) {
172→      const formatted = JSON.stringify(parsed, null, 2);
173→      setText(formatted);
174→      editorRef.current?.setValue(formatted);
175→      save(formatted);
176→      setDirty(formatted !== defaultJsonRef.current);
177→      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
178→      setError(null);
179→    } else {
180→      setError(parseErr);
181→    }
182→  }, [save]);
183→
184→  const handleSnippetSelect = useCallback(
185→    (snippet: SDUISnippet) => {
186→      setSnippetMenuOpen(false);
187→      const view = editorRef.current?.getView();
188→      if (!view) return;
189→
190→      const isScreenTemplate = snippet.category === 'screen';
191→      if (isScreenTemplate) {
192→        editorRef.current?.setValue(snippet.json);
193→        handleChange(snippet.json);
194→        return;
195→      }
196→
197→      const cursor = view.state.selection.main.head;
198→      const doc = view.state.doc.toString();
199→      const insertText = snippet.json;
200→
201→      let needsComma = false;
202→      const beforeCursor = doc.slice(0, cursor).trimEnd();
203→      if (beforeCursor.length > 0) {
204→        const lastChar = beforeCursor[beforeCursor.length - 1];
205→        if (lastChar && /[}\]"0-9a-z]/.test(lastChar)) needsComma = true;
206→      }
207→
208→      const prefix = needsComma ? ',\n' : '';
209→      view.dispatch({
210→        changes: { from: cursor, insert: prefix + insertText },
211→        selection: { anchor: cursor + prefix.length + insertText.length },
212→      });
213→      view.focus();
214→
215→      const newDoc = view.state.doc.toString();
216→      handleChange(newDoc);
217→    },
218→    [handleChange],
219→  );
220→
221→  const s = isDarkMode ? darkStyles : lightStyles;
222→
223→  if (!storyId) {
224→    return <div style={s.empty}>Select a story to edit its JSON.</div>;
225→  }
226→
227→  const isWaiting = !defaultJson && !text;
228→
229→  return (
230→    <div style={s.container}>
231→      <div style={s.toolbar}>
232→        <span style={s.label}>
233→          SDUI JSON {dirty && <span style={s.badge}>edited</span>}
234→        </span>
235→        <div style={s.actions}>
236→          <button
237→            style={s.btnSnippet}
238→            onClick={() => setSnippetMenuOpen(true)}
239→            title="Insert snippet (⌘K)"
240→          >
241→            + Snippet
242→          </button>
243→          <button
244→            style={s.btn}
245→            onClick={handleFormat}
246→            title="Format & normalize to strict JSON"
247→          >
248→            Format
249→          </button>
250→          <button
251→            style={{ ...s.btn, ...(dirty ? s.btnReset : s.btnDisabled) }}
252→            onClick={handleReset}
253→            disabled={!dirty}
254→            title="Reset to story default"
255→          >
256→            Reset
257→          </button>
258→        </div>
259→      </div>
260→
261→      {error && !isWaiting && <div style={s.error}>{error}</div>}
262→
263→      {isWaiting ? (
264→        <div style={s.empty}>
265→          Waiting for story to send SDUI JSON…
266→          <br />
267→          <span style={{ fontSize: 11, opacity: 0.7 }}>
268→            If this persists, the current story may not use useSDUIJsonEditor().
269→          </span>
270→        </div>
271→      ) : (
272→        <div style={s.editorContainer}>
273→          <CodeMirrorEditor
274→            ref={editorRef}
275→            value={text}
276→            onChange={handleChange}
277→            onValidationChange={handleValidationChange}
278→            isDarkMode={isDarkMode}
279→            onSnippetRequest={() => setSnippetMenuOpen(true)}
280→          />
281→        </div>
282→      )}
283→
284→      {snippetMenuOpen && (
285→        <SnippetMenu
286→          isDarkMode={isDarkMode}
287→          onSelect={handleSnippetSelect}
288→          onClose={() => setSnippetMenuOpen(false)}
289→        />
290→      )}
291→    </div>
292→  );
293→}
